template.css:
/* Header / Navigation Section */
.site-header {
  background: var(--card-bg, #ffffff);
  border-bottom: 1px solid var(--card-border, #e2e8f0);
  box-shadow: var(--card-shadow, 0 1px 3px rgba(0,0,0,0.06));
  position: sticky;
  top: 0;
  z-index: 100;
  width: 100%;
}
.nav-container {
  max-width: 1280px;
  margin: 0 auto;
  padding: 0 24px;
  height: 64px;
  display: flex;
  align-items: center;
  gap: 32px;
}
.nav-brand {
  font-size: var(--title-font-size, 22px);
  font-weight: var(--title-font-weight, 800);
  color: var(--title-color, #0f172a);
  text-decoration: none;
  letter-spacing: -0.5px;
  white-space: nowrap;
  flex-shrink: 0;
}
.nav-brand:hover { color: #7c3aed; }

/* Menu */
.nav-menu {
  display: flex;
  list-style: none;
  margin: 0;
  padding: 0;
  gap: 4px;
  flex: 1;
}
.nav-menu li a {
  display: block;
  padding: 8px 14px;
  font-size: var(--description-font-size, 14px);
  font-weight: var(--description-font-weight, 500);
  color: var(--description-color, #64748b);
  text-decoration: none;
  border-radius: 8px;
  transition: all 0.2s;
}
.nav-menu li a:hover { background: #f8fafc; color: #0f172a; }

/* Actions */
.nav-actions {
  display: flex;
  align-items: center;
  gap: 12px;
  flex-shrink: 0;
}
.nav-link-ghost {
  font-size: 14px;
  font-weight: 500;
  color: #64748b;
  text-decoration: none;
  padding: 8px 12px;
  border-radius: 8px;
  transition: all 0.2s;
}
.nav-link-ghost:hover { background: #f1f5f9; color: #0f172a; }
.nav-cta {
  display: inline-block;
  padding: 9px 20px;
  background: #7c3aed;
  color: var(--button-color, #fff);
  font-size: var(--button-font-size, 14px);
  font-weight: var(--button-font-weight, 700);
  border-radius: 50px;
  text-decoration: none;
  transition: all 0.2s;
  box-shadow: 0 2px 8px rgba(124,58,237,0.25);
}
.nav-cta:hover { background: #6d28d9; box-shadow: 0 4px 16px rgba(124,58,237,0.35); }

/* Mobile Toggle */
.nav-toggle {
  display: none;
  background: none;
  border: none;
  font-size: 22px;
  cursor: pointer;
  padding: 4px;
  color: #64748b;
  margin-left: auto;
}

/* Dark Mode */
.dark .site-header, [data-theme="dark"] .site-header {
  background: #0f172a;
  border-color: #1e293b;
}
.dark .nav-brand, [data-theme="dark"] .nav-brand { color: #f1f5f9; }
.dark .nav-menu li a, [data-theme="dark"] .nav-menu li a { color: #94a3b8; }
.dark .nav-menu li a:hover, [data-theme="dark"] .nav-menu li a:hover { background: #1e293b; color: #e2e8f0; }
.dark .nav-link-ghost, [data-theme="dark"] .nav-link-ghost { color: #94a3b8; }
.dark .nav-link-ghost:hover, [data-theme="dark"] .nav-link-ghost:hover { background: #1e293b; color: #e2e8f0; }

/* RTL */
[dir="rtl"] .nav-container { flex-direction: row-reverse; }
[dir="rtl"] .nav-menu { flex-direction: row-reverse; }
[dir="rtl"] .nav-actions { flex-direction: row-reverse; }

/* Responsive */
@media (max-width: 767px) {
  .nav-menu, .nav-actions { display: none; }
  .nav-toggle { display: block; }
  .nav-container { flex-wrap: wrap; height: auto; padding: 12px 16px; gap: 0; }
  .nav-brand { flex: 1; }
}
